sql:
SELECT b.name
FROM businesses b
WHERE b.business_id IN (
    SELECT f.business_id
    FROM favorites f
);

external_knowledge:
- A 'Taco Place' refers to a type of food establishment that primarily serves tacos; 
- 'SoHo' is short for "South of Houston," a neighborhood in Lower Manhattan, New York City; 
- 'active promotions' imply discounts, deals, or special offers currently being offered by businesses; 
- 'average rating' is a measure of how well a business is liked by its customers, based on review scores.

sql:
SELECT name
FROM businesses
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Taco Place');

SELECT AVG(average_rating) AS average_taco_place_rating
FROM businesses
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Taco Place');

SELECT business_id
FROM business_hours
WHERE is_open_24_hours = 1;

SELECT COUNT(*) 
   FROM businesses 
   WHERE neighborhood = (SELECT neighborhood_id FROM neighborhoods WHERE neighborhood_name = 'Tribeca');
